// build-radar.ts — generates radar SVG and HTML from blip register
import { BLIPS } from './radar-data';
import { generateRadarSVG } from './radar-svg-generator';
import { generateChangelog } from './changelog-generator';
import { writeFileSync } from 'node:fs';

// Generate the visual radar diagram
const svg = generateRadarSVG(BLIPS, {
  width: 860,
  height: 860,
  title: \`Claude Ecosystem Tech Radar — \${process.env.RADAR_EDITION ?? 'Draft'}\`,
  quadrants: ['Tooling & SDKs', 'Integrations & Patterns'],
});
writeFileSync('dist/radar.svg', svg);

// Generate the edition changelog
const changelog = generateChangelog(BLIPS, {
  previousEditionPath: 'editions/previous.json',
  edition: process.env.RADAR_EDITION ?? 'Draft',
});
writeFileSync('dist/changelog.md', changelog);

// Export blip data as JSON for downstream tooling (RFC compliance checker, etc.)
writeFileSync('dist/radar-data.json', JSON.stringify({ blips: BLIPS, edition: process.env.RADAR_EDITION }, null, 2));

console.log(\`Radar built: \${BLIPS.length} blips\`);
console.log(changelog.split('\n').slice(0, 10).join('\n'));

// scripts/check-radar-compliance.mjs
import { readFileSync } from 'node:fs';

interface Blip { id: string; name: string; ring: string; rationale: string; }
interface RadarData { blips: Blip[]; edition: string; }

const args = process.argv.slice(2);
const radarPath = args[args.indexOf('--radar') + 1];
const failOnRing = args[args.indexOf('--fail-on') + 1] ?? 'hold';
const bodyIdx = args.indexOf('--body');
const body = bodyIdx >= 0 ? args[bodyIdx + 1] : '';

const { blips }: RadarData = JSON.parse(readFileSync(radarPath, 'utf8'));

const violations: string[] = [];
const warnings: string[] = [];

for (const blip of blips) {
  const mentioned = body.toLowerCase().includes(blip.name.toLowerCase());
  if (!mentioned) continue;

  if (blip.ring === failOnRing) {
    violations.push(
      `❌ "${blip.name}" is in HOLD ring.\n   Reason: ${blip.rationale.slice(0, 120)}...`
    );
  } else if (blip.ring === 'assess') {
    warnings.push(
      `⚠️  "${blip.name}" is in ASSESS ring — not approved for production use.`
    );
  }
}

if (warnings.length > 0) {
  console.warn('\n--- Radar warnings ---');
  warnings.forEach((w) => console.warn(w));
}

if (violations.length > 0) {
  console.error('\n--- Radar compliance violations ---');
  violations.forEach((v) => console.error(v));
  console.error('\nRequest an architecture board exception to proceed.');
  process.exit(1);
}

console.log('✅ Radar compliance check passed.');
